  `ticker` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'д»Јз Ғ',
  `type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'STOCK' COMMENT 'зұ»еһӢпјҡSTOCK-иӮЎзҘЁпјҢBOND-еҖәеҲё',
  `ts` date NOT NULL COMMENT 'ж—Ҙжңҹ',
  `open` decimal(10, 4) NOT NULL COMMENT 'ејҖзӣҳд»·',
  `high` decimal(10, 4) NOT NULL COMMENT 'жңҖй«ҳд»·',
  `low` decimal(10, 4) NOT NULL COMMENT 'жңҖдҪҺд»·',
  `close` decimal(10, 4) NOT NULL COMMENT 'ж”¶зӣҳд»·',
  `volume` bigint NOT NULL COMMENT 'жҲҗдәӨйҮҸ',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'еҲӣе»әж—¶й—ҙ',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_ticker_ts_type`(`ticker` ASC, `ts` ASC, `type` ASC) USING BTREE,
  INDEX `idx_ticker`(`ticker` ASC) USING BTREE,
  INDEX `idx_ts`(`ts` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1000 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = DYNAMIC;





